const cp = require('child_process');
const scanDir = '__DOCUMENTS_DIR__';
const projRoot = '__PROJECT_ROOT__';

try {
  const raw = cp.execSync('bash scripts/scan-projects.sh "' + scanDir + '" 2>&1', {cwd: projRoot, timeout: 60000, encoding: 'utf8'});
  const now = Math.floor(Date.now() / 1000);
  const agentProjects = raw.trim().split(String.fromCharCode(10)).filter(l => l.includes('|true|')).map(l => {
    const parts = l.split('|');
    const age = parseInt(parts[3]) || 0;
    const days = age ? Math.floor((now - age) / 86400) : 999;
    return {name: parts[0], days};
  }).filter(p => p.days <= 7);

  const alerts = [];
  for (const p of agentProjects) {
    const path = scanDir + '/' + p.name;
    try {
      const output = cp.execSync('bash scripts/check-drift.sh 2>&1', {cwd: path, timeout: 30000, encoding: 'utf8'});
      const w = parseInt((output.match(/(\d+) warnings/) || [,'0'])[1]);
      const e = parseInt((output.match(/(\d+) errors/) || [,'0'])[1]);
      if (w > 0 || e > 0) alerts.push({project: p.name, warnings: w, errors: e});
    } catch(err) {
      alerts.push({project: p.name, warnings: 0, errors: 1, error: 'check-drift failed'});
    }
  }

  return [{json: {
    status: 'complete', checked: agentProjects.length, total_alerts: alerts.length,
    message: alerts.length === 0 ? 'All active projects healthy' : alerts.length + ' project(s) need attention',
    alerts, timestamp: new Date().toISOString()
  }}];
} catch(e) {
  return [{json: {status: 'error', error: (e.stderr || '') + e.message}}];
}
